### Example 2: Spring Boot `OncePerRequestFilter` that validates raw body before binding

This prevents `@RequestBody` from triggering Jackson databind before validation.

```java
import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.springframework.web.filter.OncePerRequestFilter;
import org.springframework.web.util.ContentCachingRequestWrapper;

import java.io.IOException;
import java.io.ByteArrayInputStream;
import java.util.Set;

public class RawJsonValidationFilter extends OncePerRequestFilter {

  private final RawJsonPolicyValidator validator = new RawJsonPolicyValidator(
      100, // maxDepth
      500, // maxFieldsPerObject
      Set.of("@class", "@type"),
      true // rejectJavascriptSampler
  );

  @Override
  protected boolean shouldNotFilter(HttpServletRequest request) {
    // Apply only to the sensitive endpoint(s)
    return !request.getRequestURI().equals("/druid/indexer/v1/sampler");
  }

  @Override
  protected void doFilterInternal(HttpServletRequest request,
                                  HttpServletResponse response,
                                  FilterChain filterChain) throws ServletException, IOException {

    ContentCachingRequestWrapper wrapped = new ContentCachingRequestWrapper(request);

    try {
      // Force caching by reading the input stream once here:
      byte[] body = wrapped.getInputStream().readAllBytes();

      // Validate raw JSON before any controller binding occurs
      validator.validate(new ByteArrayInputStream(body));

      // Continue the chain with a wrapper that can re-serve cached bytes
      filterChain.doFilter(wrapped, response);
    } catch (RawJsonPolicyValidator.Violation v) {
      response.setStatus(400);
      response.setContentType("application/json");
      response.getWriter().write("{\"error\":\"invalid_request\"}");
      // Log v.getMessage() with request id and caller identity (do not echo payload)
    }
  }
}
```

Pitfall: if something earlier in the chain already reads/deserializes the body, you lose the opportunity. Ensure ordering: this filter must run **before** framework components that bind `@RequestBody`.

