### Example 4: Test cases for empty keys, duplicates, and sampler JavaScript policy

```java
import org.junit.jupiter.api.Test;

import java.io.ByteArrayInputStream;
import java.nio.charset.StandardCharsets;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;

public class RawJsonPolicyValidatorTest {

  RawJsonPolicyValidator v = new RawJsonPolicyValidator(
      50, 200, Set.of("@class", "@type"), true
  );

  @Test
  void rejectsEmptyKey() {
    String json = "{\"name\":\"ok\",\"\":\"bad\"}";
    assertThrows(RawJsonPolicyValidator.Violation.class,
        () -> v.validate(new ByteArrayInputStream(json.getBytes(StandardCharsets.UTF_8))));
  }

  @Test
  void rejectsDuplicateKey() {
    String json = "{\"role\":\"user\",\"role\":\"admin\"}";
    assertThrows(RawJsonPolicyValidator.Violation.class,
        () -> v.validate(new ByteArrayInputStream(json.getBytes(StandardCharsets.UTF_8))));
  }

  @Test
  void rejectsJavascriptSamplerFilter() {
    String json = """
      {
        "type":"index",
        "spec":{
          "dataSchema":{
            "transformSpec":{
              "filter":{
                "type":"javascript",
                "function":"function(){java.lang.Runtime.getRuntime().exec('malicious_command');}"
              }
            }
          }
        }
      }""";
    assertThrows(RawJsonPolicyValidator.Violation.class,
        () -> v.validate(new ByteArrayInputStream(json.getBytes(StandardCharsets.UTF_8))));
  }

  @Test
  void acceptsBenign() throws Exception {
    String json = "{\"a\":1,\"b\":{\"c\":2}}";
    v.validate(new ByteArrayInputStream(json.getBytes(StandardCharsets.UTF_8)));
  }
}
```

